// Rocket Ship — a retro toy rocket. Parametric & colorable.
//
//   body   : cylindrical fuselage
//   nose   : conical nose cone on top
//   fins    : N tail fins around the base (one shared label -> one color)
//   window : round porthole on the body (toggle)
//   exhaust: flared nozzle at the bottom
//
// Knobs are exposed via api.params(...) -> live Parameters panel.
// Each region is wrapped in api.label(...) BEFORE the union so the colors
// can be painted by name afterward (labels ride through .add()/.subtract()).

const { Manifold, CrossSection } = api;

const p = api.params({
  bodyRadius: { type: 'number', default: 14, min: 8,  max: 24, step: 0.5, unit: 'mm', label: 'Body radius' },
  bodyHeight: { type: 'number', default: 46, min: 24, max: 80, step: 1,   unit: 'mm', label: 'Body height' },
  noseHeight: { type: 'number', default: 26, min: 10, max: 50, step: 1,   unit: 'mm', label: 'Nose height' },
  finCount:   { type: 'int',    default: 4,  min: 0,  max: 8,              label: 'Fin count' },
  finSweep:   { type: 'number', default: 16, min: 6,  max: 30, step: 0.5, unit: 'mm', label: 'Fin reach' },
  window:     { type: 'boolean', default: true, label: 'Porthole window' },
  windowSize: { type: 'number', default: 6, min: 3, max: 11, step: 0.5, unit: 'mm', label: 'Window radius' },
});

const R = p.bodyRadius;

// --- Body: cylinder, base at z=0 -------------------------------------------
const body = Manifold.cylinder(p.bodyHeight, R, R);

// --- Nose: cone sitting on top of the body, overlapping by 1mm to fuse -----
const OVERLAP = 1;
const nose = Manifold.cylinder(p.noseHeight + OVERLAP, R, 0)
  .translate([0, 0, p.bodyHeight - OVERLAP]);

// --- Exhaust nozzle: flared truncated cone hanging below the base ----------
// Narrow throat where it meets the body, flaring out toward the bottom.
const nozzleH = R * 0.9;
const throatR = R * 0.62;
const bellR   = R * 0.92;
// Build it base-up then flip so the wide bell points down (-Z).
const nozzle = Manifold.cylinder(nozzleH + OVERLAP, throatR, bellR)
  .rotate([180, 0, 0])                      // flip: wide end now at -Z
  .translate([0, 0, OVERLAP]);              // throat overlaps into the body

// --- Fins: a swept triangular fin, patterned around the base --------------
// Profile in the X(radial)/Z(height) plane, extruded thin along Y, then
// stood up against the body. The fin hugs the body for ~40% of its height
// and sweeps out + down past the base for that classic tail-fin look.
const finBase   = p.bodyHeight * 0.42;       // how far up the body the fin reaches
const finDrop   = R * 0.55;                   // how far below the base it dips
const finThick  = Math.max(2, R * 0.22);
const reach     = p.finSweep;                 // outward sweep distance
const finProfile = CrossSection.ofPolygons([[
  [R - 1.2,            finBase],             // top, tucked into the body
  [R - 1.2,            0],                    // bottom-inner at the base
  [R + reach,         -finDrop],             // outer tip, swept down & out
]]);
const fin = api.label(
  finProfile
    .extrude(finThick, 0, 0, 0, true)        // centered in Y, thickness finThick
    .rotate([90, 0, 0]),                       // stand the profile up (XY->XZ)
  'fins',
);

// Assemble the colored solid pieces -----------------------------------------
const parts = [
  api.label(body, 'body'),
  api.label(nose, 'nose'),
  api.label(nozzle, 'exhaust'),
];
if (p.finCount > 0) {
  // One label, one color shared by every fin in the ring.
  parts.push(api.circularPattern(fin, p.finCount, { axis: 'z' }));
}

let rocket = api.expectUnion(parts, { expectComponents: 1 });

// --- Porthole window: a framed glass disc on the body's +Y side -----------
// Centered ~62% up the body, facing +Y. No subtraction (which would tunnel
// the wall and split the solid) — instead we ADD two overlapping pucks:
//   * a frame ring (stays "body") standing a touch proud of the surface, and
//   * a glass disc ("window") seated inside it, sunk deep enough to overlap
//     the body wall so the whole thing fuses into one solid.
if (p.window) {
  const winR   = Math.min(p.windowSize, R - 2);   // keep a body-frame margin
  const winZ   = p.bodyHeight * 0.62;
  const frameW = 1.6;                              // ring wall thickness
  const proud  = 1.4;                              // how far the frame stands out
  const sink   = 3;                                // how deep pucks reach inward
  const at     = (puck) => puck.rotate([-90, 0, 0]).translate([0, R - sink, winZ]);
  // Frame ring: outer disc minus inner disc, both axis-aligned to +Y. The
  // inner bore is cut 0.4 *under* winR so the glass below overlaps the ring
  // wall volumetrically instead of sharing a coincident face (a coincident
  // wall leaves a zero-thickness shard that splits the solid at large R).
  const ring = api.label(
    at(Manifold.cylinder(sink + proud, winR + frameW, winR + frameW)
        .subtract(Manifold.cylinder(sink + proud + 2, winR - 0.4, winR - 0.4).translate([0, 0, -1]))),
    'body',
  );
  // Glass disc: fills the ring (overlapping its bore by 0.4) and reaches
  // `sink` into the wall so the whole porthole fuses into one solid.
  const glass = api.label(
    at(Manifold.cylinder(sink + proud - 0.4, winR, winR)),
    'window',
  );
  rocket = rocket.add(ring).add(glass);
}

return rocket;

